def load_pixmap(b64: str) -> QPixmap:
    pixmap = QPixmap()
    pixmap.loadFromData(_decode(b64))
    return pixmap

def load_app_icon() -> QIcon:
    icon = QIcon()
    ico_pixmap = load_pixmap(APP_ICON_ICO_B64)
    if not ico_pixmap.isNull():
        icon.addPixmap(ico_pixmap)
    else:
        fallback = load_pixmap(AIO_PNG_B64)
        if not fallback.isNull():
            icon.addPixmap(fallback)
    return icon
